import dspy

class ToolLoopDetector:
    def __init__(self, max_repeats=3):
        self.tool_history = {}
        self.max_repeats = max_repeats

    def check_loop(self, tool_call):
        tool_sig = (tool_call.get('name'), tool_call.get('args', {}))
        count = self.tool_history.get(tool_sig, 0) + 1
        self.tool_history[tool_sig] = count
        return count >= self.max_repeats

# Usage in DSPy module
class LoopAwareReAct(dspy.Module):
    def __init__(self):
        super().__init__()
        self.detector = ToolLoopDetector()

    def forward(self, **kwargs):
        # ... tool calling logic
        if self.detector.check_loop(tool_call):
            raise ValueError(f'Tool loop detected: {tool_call}')
        return response

import dspy
import hashlib

class StateLoopDetector:
    def __init__(self, window=5):
        self.state_hashes = []
        self.window = window

    def update_and_check(self, context, tool_history):
        state_str = f'{context}|{tool_history}'
        state_hash = hashlib.md5(state_str.encode()).hexdigest()

        self.state_hashes.append(state_hash)
        if len(self.state_hashes) > self.window:
            self.state_hashes.pop(0)

        return len(set(self.state_hashes)) < len(self.state_hashes)

# Integrate in DSPy forward
class SafeAgent(dspy.Module):
    def forward(self, question):
        detector = StateLoopDetector()
        for step in range(10):
            if detector.update_and_check(question, self.history):
                dspy.warn('State loop detected', level='ERROR')
                break
            response = self.predict(question)
        return response

import dspy
import inspect

class StackLoopDetector:
    def __init__(self):
        self.call_stack = []

    def enter_module(self, module_name, tool_call):
        self.call_stack.append((module_name, tool_call))
        if len(self.call_stack) > 1 and self.call_stack[-2:] == self.call_stack[-4:-2]:
            return True
        return False

    def exit_module(self):
        self.call_stack.pop()

# DSPy wrapper
original_forward = dspy.Module.forward

def monitored_forward(self, *args, **kwargs):
    detector = StackLoopDetector()
    if detector.enter_module(self.__class__.__name__, kwargs.get('tool_call')):
        raise RuntimeError('Recursive tool loop detected')
    try:
        return original_forward(self, *args, **kwargs)
    finally:
        detector.exit_module()

dspy.Module.forward = monitored_forward

