    thought = dspy.OutputField()
    tool_call = dspy.OutputField(desc='JSON {"name": str, "args": dict} or null')
    answer = dspy.OutputField()

class BlacklistAgent(dspy.Module):
    def __init__(self):
        super().__init__()
        self.react = dspy.ChainOfThought(LoopProofReAct)
        self.blacklist = set()

    def forward(self, question):
        recent_tools = list(self.blacklist)[-3:]  # last 3 tools
        pred = self.react(question=question, recent_tools=str(recent_tools))

        if pred.tool_call and pred.tool_call not in self.blacklist:
            tool_sig = (pred.tool_call.get('name'), str(pred.tool_call.get('args')))
            self.blacklist.add(tool_sig)
        elif pred.tool_call:
            pred.tool_call = None  # Block repeat
            pred.answer = 'Cannot proceed: tool repetition detected.'

        return dspy.Prediction(answer=pred.answer, tool_call=pred.tool_call)

